module tb;

  // Timescale declaration
  `timescale 1ns/1ps

  // Testbench signals
  // Declare a wire to connect to the DUT's 'zero' output
  wire tb_zero;

  // Instantiate the Design Under Test (DUT)
  TopModule top_module1 (
    .zero(tb_zero)
  );

  // Simulation Timeout
  // This block will terminate the simulation if it runs for too long.
  initial begin
    #1000000; // Wait for 1,000,000 ns
    $display("TIMEOUT: Simulation exceeded maximum allowed time.");
    $finish;
  end

  // Test Stimuli and Output Verification
  initial begin
    // Since the DUT is a simple combinational circuit with no inputs,
    // we just need to wait a minimal time for the output to settle
    // and then check its value.
    #10; // Wait for 10 time units (10ns) for propagation

    // Verify the 'zero' output
    if (tb_zero == 1'b0) begin
      $display("PASS");
    end else begin
      // Report failure with details if 'zero' is not 0
      $display("FAIL: Output 'zero' is %b, but expected 1'b0.", tb_zero);
    end

    // End the simulation after all checks are complete
    $finish;
  end

endmodule

`timescale 1ns/1ps

module tb;

  // DUT Output Wires
  wire dut_out;

  // Instantiate the DUT
  TopModule top_module1 (
    .out (dut_out)
  );

  // Test sequence
  initial begin
    // Give some time for potential X propagation or initial values to settle, though not strictly needed for combinational
    #10;

    // Check the output
    if (dut_out == 1'b0) begin
      $display("PASS");
    end else begin
      $display("FAIL: Output 'out' is %b, expected 0.", dut_out);
    end

    // End simulation
    $finish;
  end

  // Simulation timeout
  initial begin
    #1000000; // 1ms timeout
    $display("TIMEOUT");
    $finish;
  end

endmodule

