module tb;

  // Declare testbench signals for connecting to DUT ports
  // 'one_o' is declared as a wire because it is driven by the DUT.
  wire one_o;

  // Instantiate the DUT module
  TopModule top_module1 (
    .one(one_o) // Connect DUT output 'one' to testbench signal 'one_o'
  );

  // Test sequence and output verification
  initial begin
    $display("--------------------------------------------------");
    $display("Starting simulation for TopModule verification...");
    $display("--------------------------------------------------");

    // Allow a small delay for combinational logic to settle at time 0
    #1;

    // --- Test Case 1: Check output 'one' at initial time ---
    $display("INFO: Time %0t: Checking output 'one_o'...", $time);
    if (one_o === 1'b1) begin
      $display("INFO: Time %0t: Test Case 1 Passed. 'one_o' is 1 (Expected: 1).", $time);
    end else begin
      $display("FAIL: Time %0t: Test Case 1 Failed. Expected 'one_o' to be 1, but got %b.", $time, one_o);
      $finish; // Terminate simulation on first failure
    end

    // Introduce some delay and check again to ensure constant output
    #10;

    // --- Test Case 2: Check output 'one' after some time ---
    $display("INFO: Time %0t: Re-checking output 'one_o' after delay...", $time);
    if (one_o === 1'b1) begin
      $display("INFO: Time %0t: Test Case 2 Passed. 'one_o' is 1 (Expected: 1).", $time);
    end else begin
      $display("FAIL: Time %0t: Test Case 2 Failed. Expected 'one_o' to be 1, but got %b.", $time, one_o);
      $finish; // Terminate simulation on failure
    end

    // Introduce more delay and check again
    #20;

    // --- Test Case 3: Check output 'one' after more time ---
    $display("INFO: Time %0t: Final check on output 'one_o'...", $time);
    if (one_o === 1'b1) begin
      $display("INFO: Time %0t: Test Case 3 Passed. 'one_o' is 1 (Expected: 1).", $time);
    end else begin
      $display("FAIL: Time %0t: Test Case 3 Failed. Expected 'one_o' to be 1, but got %b.", $time, one_o);
      $finish; // Terminate simulation on failure
    end

    $display("--------------------------------------------------");
    $display("All checks completed. DUT behaves as expected.");
    $display("PASS"); // Report overall pass
    $finish; // End simulation

  end

  // Timeout to prevent infinite simulation
  initial begin
    #1000000 $display("TIMEOUT: Simulation exceeded maximum allowed time.");
    $finish; // Terminate simulation
  end

endmodule

