module tb;

  // Declare testbench signals
  reg  [31:0] in_tb;
  wire [31:0] out_tb;

  // Variable to track test status
  reg  integer error_count;

  // Instantiate the DUT
  TopModule top_module1 (
    .in  (in_tb),
    .out (out_tb)
  );

  // Timeout for simulation
  initial begin
    #1000000 $display("TIMEOUT");
    $finish;
  end

  // Test sequence
  initial begin
    error_count = 0;

    // Initialize inputs
    in_tb = 32'h00000000;
    #10; // Allow time for combinational logic to propagate

    $display("--------------------------------------------------");
    $display("Starting byte order reversal testbench...");
    $display("--------------------------------------------------");

    // Test Case 1: All zeros
    test_case(32'h00000000, 32'h00000000, "All Zeros");

    // Test Case 2: All ones
    test_case(32'hFFFFFFFF, 32'hFFFFFFFF, "All Ones");

    // Test Case 3: Simple increasing sequence
    test_case(32'h12345678, 32'h78563412, "Simple Sequence 1");

    // Test Case 4: Another simple sequence
    test_case(32'hAABBCCDD, 32'hDDCCBBAA, "Simple Sequence 2");

    // Test Case 5: Single non-zero byte (LSB)
    test_case(32'h000000FF, 32'hFF000000, "LSB Byte Only");

    // Test Case 6: Single non-zero byte (Byte 1)
    test_case(32'h0000FF00, 32'h00FF0000, "Byte 1 Only");

    // Test Case 7: Single non-zero byte (Byte 2)
    test_case(32'h00FF0000, 32'h0000FF00, "Byte 2 Only");

    // Test Case 8: Single non-zero byte (MSB)
    test_case(32'hFF000000, 32'h000000FF, "MSB Byte Only");

    // Test Case 9: Alternating bytes
    test_case(32'h55AA55AA, 32'hAA55AA55, "Alternating Bytes 1");

    // Test Case 10: Another alternating bytes
    test_case(32'hAA55AA55, 32'h55AA55AA, "Alternating Bytes 2");

    // Test Case 11: Mixed bytes
    test_case(32'h0123ABCD, 32'hCDAB2301, "Mixed Bytes 1");

    // Test Case 12: More mixed bytes
    test_case(32'hF0E1D2C3, 32'hC3D2E1F0, "Mixed Bytes 2");

    // Test Case 13: Edge value for a byte (0x01)
    test_case(32'h00000001, 32'h01000000, "LSB 0x01");

    // Test Case 14: Edge value for a byte (0xFE)
    test_case(32'h0000FE00, 32'h00FE0000, "Byte 1 0xFE");


    $display("--------------------------------------------------");
    if (error_count == 0) begin
      $display("PASS: All tests completed successfully.");
    end else begin
      $display("FAIL: %0d errors found during testing.", error_count);
    end
    $display("--------------------------------------------------");
    $finish;
  end

  // Task to perform a single test case
  task test_case;
    input [31:0] input_val;
    input [31:0] expected_val;
    input        [8*20:1] test_name; // Max 20 characters for test name

    begin
      in_tb = input_val;
      #10; // Wait for combinational logic to settle

      if (out_tb === expected_val) begin
        $display("TEST_CASE: %s - Input: 0x%h, Expected: 0x%h, Got: 0x%h - PASS", 
                 test_name, input_val, expected_val, out_tb);
      end else begin
        $display("TEST_CASE: %s - Input: 0x%h, Expected: 0x%h, Got: 0x%h - FAIL", 
                 test_name, input_val, expected_val, out_tb);
        error_count = error_count + 1;
      end
    end
  endtask

endmodule

