module tb;

  // Timescale declaration
  `timescale 1ns/1ps

  // Testbench signals
  reg [2:0] in_tb;
  wire [1:0] out_tb;

  // Testbench variables
  reg integer i;            // Loop counter for inputs
  reg integer expected_out; // Calculated expected output
  reg integer error_count;  // Counter for failed tests
  reg integer test_count;   // Counter for total tests run

  // Instantiate the Design Under Test (DUT)
  TopModule top_module1 (
    .in  (in_tb),
    .out (out_tb)
  );

  // Test stimulus generation and output verification
  initial begin
    // Initialize test variables
    error_count = 0;
    test_count = 0;
    in_tb = 3'b000; // Initialize input to a known state

    $display("---------------------------------------------------");
    $display("Starting TopModule Population Count Testbench");
    $display("---------------------------------------------------");

    // Loop through all possible 3-bit input combinations (0 to 7)
    for (i = 0; i < 8; i = i + 1) begin
      in_tb = i; // Apply current input value
      #10;       // Wait for combinational logic to settle (arbitrary delay)

      // Calculate the expected output (population count)
      // Verilog treats single bits in arithmetic expressions as 0 or 1.
      expected_out = in_tb[0] + in_tb[1] + in_tb[2];

      // Check if the DUT's output matches the expected output
      if (out_tb === expected_out) begin
        $display("PASS: Test %0d | in = 3'b%b, Expected out = 2'b%b, Actual out = 2'b%b",
                 test_count, in_tb, expected_out, out_tb);
      end else begin
        $display("FAIL: Test %0d | in = 3'b%b, Expected out = 2'b%b, Actual out = 2'b%b",
                 test_count, in_tb, expected_out, out_tb);
        error_count = error_count + 1;
      end
      test_count = test_count + 1;
    end

    $display("---------------------------------------------------");
    $display("Test Summary:");
    $display("Total tests run: %0d", test_count);
    $display("Total errors: %0d", error_count);
    if (error_count == 0) begin
      $display("PASS: All tests completed successfully.");
    end else begin
      $display("FAIL: %0d test(s) failed.", error_count);
    end
    $display("---------------------------------------------------");

    $finish; // End the simulation
  end

  // Timeout to prevent infinite simulation
  initial begin
    #1000000 $display("TIMEOUT: Simulation exceeded maximum allowed time.");
    $finish;
  end

endmodule

