module tb;

  // Declare testbench signals
  reg x_tb;
  reg y_tb;
  wire z_dut; // Output from DUT

  // Declare variables for test case tracking and pass/fail status
  integer test_case_count;
  reg all_tests_passed; // Use reg for boolean flags

  // Instantiate the DUT
  TopModule top_module1 (
    .x(x_tb),
    .y(y_tb),
    .z(z_dut)
  );

  // Timeout to prevent infinite simulation
  initial begin
    #1000000 $display("TIMEOUT: Simulation exceeded maximum allowed time.");
    $finish;
  end

  // Test stimulus generation and output checking
  initial begin
    test_case_count = 0;
    all_tests_passed = 1; // Assume all tests pass initially

    // Initial values for inputs
    x_tb = 1'b0;
    y_tb = 1'b0;

    // Give some time for initial values to propagate
    #10;

    $display("---------------------------------------------------");
    $display("Starting TopModule Testbench for z = (x^y) & x");
    $display("---------------------------------------------------");

    // Test Case 1: x=0, y=0 => z = (0^0) & 0 = 0 & 0 = 0
    test_case_count = test_case_count + 1;
    x_tb = 1'b0;
    y_tb = 1'b0;
    #10; // Wait for combinational logic to settle
    if (z_dut !== 1'b0) begin
      $display("FAIL: Test Case %0d (x=%b, y=%b). Expected z=0, Got z=%b", test_case_count, x_tb, y_tb, z_dut);
      all_tests_passed = 0;
    end else begin
      $display("PASS: Test Case %0d (x=%b, y=%b). z=%b", test_case_count, x_tb, y_tb, z_dut);
    end

    // Test Case 2: x=0, y=1 => z = (0^1) & 0 = 1 & 0 = 0
    test_case_count = test_case_count + 1;
    x_tb = 1'b0;
    y_tb = 1'b1;
    #10;
    if (z_dut !== 1'b0) begin
      $display("FAIL: Test Case %0d (x=%b, y=%b). Expected z=0, Got z=%b", test_case_count, x_tb, y_tb, z_dut);
      all_tests_passed = 0;
    end else begin
      $display("PASS: Test Case %0d (x=%b, y=%b). z=%b", test_case_count, x_tb, y_tb, z_dut);
    end

    // Test Case 3: x=1, y=0 => z = (1^0) & 1 = 1 & 1 = 1
    test_case_count = test_case_count + 1;
    x_tb = 1'b1;
    y_tb = 1'b0;
    #10;
    if (z_dut !== 1'b1) begin
      $display("FAIL: Test Case %0d (x=%b, y=%b). Expected z=1, Got z=%b", test_case_count, x_tb, y_tb, z_dut);
      all_tests_passed = 0;
    end else begin
      $display("PASS: Test Case %0d (x=%b, y=%b). z=%b", test_case_count, x_tb, y_tb, z_dut);
    end

    // Test Case 4: x=1, y=1 => z = (1^1) & 1 = 0 & 1 = 0
    test_case_count = test_case_count + 1;
    x_tb = 1'b1;
    y_tb = 1'b1;
    #10;
    if (z_dut !== 1'b0) begin
      $display("FAIL: Test Case %0d (x=%b, y=%b). Expected z=0, Got z=%b", test_case_count, x_tb, y_tb, z_dut);
      all_tests_passed = 0;
    end else begin
      $display("PASS: Test Case %0d (x=%b, y=%b). z=%b", test_case_count, x_tb, y_tb, z_dut);
    end

    $display("---------------------------------------------------");
    // Report final test status
    if (all_tests_passed) begin
      $display("ALL TESTS PASSED");
    end else begin
      $display("SOME TESTS FAILED");
    end
    $display("---------------------------------------------------");

    $finish; // End the simulation
  end

endmodule

