module tb;

  // Declare testbench signals
  reg a;
  reg b;
  wire out;

  // Declare variables for test control and error reporting
  integer errors;
  integer test_count;
  reg expected_out;

  // Instantiate the Design Under Test (DUT)
  TopModule top_module1 (
    .a   (a),
    .b   (b),
    .out (out)
  );

  // Timeout mechanism
  initial begin
    #1000000 $display("TIMEOUT");
    $finish;
  end

  // Test sequence
  initial begin
    errors = 0;
    test_count = 0;

    $display("--------------------------------------------------");
    $display("Starting TopModule NOR gate testbench");
    $display("--------------------------------------------------");

    // Test Case 1: a=0, b=0
    a = 0;
    b = 0;
    expected_out = 1; // 0 NOR 0 = 1
    #10; // Allow time for combinational logic to propagate
    test_count = test_count + 1;
    if (out !== expected_out) begin
      $display("FAIL: Test %0d (a=%0d, b=%0d): Expected out=%0d, Got out=%0d", test_count, a, b, expected_out, out);
      errors = errors + 1;
    end else begin
      $display("PASS: Test %0d (a=%0d, b=%0d): Expected out=%0d, Got out=%0d", test_count, a, b, expected_out, out);
    end

    // Test Case 2: a=0, b=1
    a = 0;
    b = 1;
    expected_out = 0; // 0 NOR 1 = 0
    #10;
    test_count = test_count + 1;
    if (out !== expected_out) begin
      $display("FAIL: Test %0d (a=%0d, b=%0d): Expected out=%0d, Got out=%0d", test_count, a, b, expected_out, out);
      errors = errors + 1;
    end else begin
      $display("PASS: Test %0d (a=%0d, b=%0d): Expected out=%0d, Got out=%0d", test_count, a, b, expected_out, out);
    end

    // Test Case 3: a=1, b=0
    a = 1;
    b = 0;
    expected_out = 0; // 1 NOR 0 = 0
    #10;
    test_count = test_count + 1;
    if (out !== expected_out) begin
      $display("FAIL: Test %0d (a=%0d, b=%0d): Expected out=%0d, Got out=%0d", test_count, a, b, expected_out, out);
      errors = errors + 1;
    end else begin
      $display("PASS: Test %0d (a=%0d, b=%0d): Expected out=%0d, Got out=%0d", test_count, a, b, expected_out, out);
    end

    // Test Case 4: a=1, b=1
    a = 1;
    b = 1;
    expected_out = 0; // 1 NOR 1 = 0
    #10;
    test_count = test_count + 1;
    if (out !== expected_out) begin
      $display("FAIL: Test %0d (a=%0d, b=%0d): Expected out=%0d, Got out=%0d", test_count, a, b, expected_out, out);
      errors = errors + 1;
    end else begin
      $display("PASS: Test %0d (a=%0d, b=%0d): Expected out=%0d, Got out=%0d", test_count, a, b, expected_out, out);
    end

    $display("--------------------------------------------------");
    if (errors == 0) begin
      $display("All %0d tests passed. PASS", test_count);
    end else begin
      $display("%0d out of %0d tests failed. FAIL", errors, test_count);
    end
    $display("--------------------------------------------------");

    $finish;
  end

endmodule

