module tb;

  // Testbench signals
  reg clk;
  reg reset;
  reg [7:0] d;
  wire [7:0] q;

  // Test status variables
  integer errors;
  integer i; // Loop counter

  // Instantiate the Design Under Test (DUT)
  TopModule top_module1 (
    .clk(clk),
    .reset(reset),
    .d(d),
    .q(q)
  );

  // Clock generation
  initial begin
    clk = 0;
    forever #5 clk = ~clk; // 10ns period, 100 MHz clock
  end

  // Simulation timeout
  initial begin
    #1000000 $display("TIMEOUT: Simulation took too long.");
    $finish;
  end

  // Test sequence
  initial begin
    // Initialize signals
    reset  = 1; // Assert reset initially
    d      = 8'h00;
    errors = 0;

    $display("--------------------------------------------------");
    $display("INFO: Starting testbench for TopModule");
    $display("--------------------------------------------------");

    // 1. Initial Reset Test
    // Wait for a few clock cycles with reset asserted to ensure stable state
    #10; // Allow signals to settle
    $display("INFO: Applying initial reset.");
    @(negedge clk); // Sample q after a negative edge with reset active
    if (q !== 8'h34) begin
      $display("FAIL: Initial reset value incorrect. Expected 8'h34, got 8'h%h", q);
      errors = errors + 1;
    end else begin
      $display("PASS: Initial reset value correct. q = 8'h%h", q);
    end

    // De-assert reset
    reset = 0;
    #10; // Allow reset to propagate

    // 2. Normal Data Loading Test
    $display("INFO: Testing normal data loading.");
    for (i = 0; i < 256; i = i + 1) begin
      d = i;
      @(negedge clk); // Data should be loaded on this negative edge
      if (q !== d) begin
        $display("FAIL: Data load failed for d=8'h%h. Expected 8'h%h, got 8'h%h", i, d, q);
        errors = errors + 1;
      end
    end
    $display("INFO: Completed basic data loading test.");

    // 3. Edge Cases: Specific Data Values
    $display("INFO: Testing specific data values.");
    d = 8'h00;
    @(negedge clk);
    if (q !== 8'h00) begin $display("FAIL: Data load 0x00 failed. Expected 0x00, got 8'h%h", q); errors = errors + 1; end

    d = 8'hFF;
    @(negedge clk);
    if (q !== 8'hFF) begin $display("FAIL: Data load 0xFF failed. Expected 0xFF, got 8'h%h", q); errors = errors + 1; end

    d = 8'hAA; // Alternating bits
    @(negedge clk);
    if (q !== 8'hAA) begin $display("FAIL: Data load 0xAA failed. Expected 0xAA, got 8'h%h", q); errors = errors + 1; end

    d = 8'h55; // Alternating bits
    @(negedge clk);
    if (q !== 8'h55) begin $display("FAIL: Data load 0x55 failed. Expected 0x55, got 8'h%h", q); errors = errors + 1; end
    $display("INFO: Completed specific data value tests.");

    // 4. Reset During Operation Test
    $display("INFO: Testing reset assertion during normal operation.");
    d = 8'h12; // Load some data
    @(negedge clk);
    if (q !== 8'h12) begin $display("FAIL: Pre-reset load failed. Expected 8'h12, got 8'h%h", q); errors = errors + 1; end
    $display("INFO: Loaded d=8'h12, q = 8'h%h", q);

    reset = 1; // Assert reset
    d     = 8'hAB; // Change data while reset is asserted (should be ignored)
    #5; // Ensure reset is stable before the next negative edge
    @(negedge clk); // Reset should take effect on this edge
    if (q !== 8'h34) begin
      $display("FAIL: Reset during operation failed. Expected 8'h34, got 8'h%h", q);
      errors = errors + 1;
    end else begin
      $display("PASS: Reset during operation correct. q = 8'h%h", q);
    end

    reset = 0; // De-assert reset
    #5; // Ensure reset is low before the next negative edge
    @(negedge clk); // New data (8'hAB) should be loaded now
    if (q !== 8'hAB) begin
      $display("FAIL: Post-reset data load failed. Expected 8'hAB, got 8'h%h", q);
      errors = errors + 1;
    end else begin
      $display("PASS: Post-reset data load correct. q = 8'h%h", q);
    end
    $display("INFO: Completed reset during operation test.");

    // 5. Short Pulse Reset Test (Edge case: reset asserted for one cycle)
    $display("INFO: Testing short pulse reset.");
    d = 8'hCD;
    @(negedge clk); // Load 0xCD
    if (q !== 8'hCD) begin $display("FAIL: Pre-short-reset load failed. Expected 8'hCD, got 8'h%h", q); errors = errors + 1; end

    reset = 1;
    d     = 8'hEF; // Data changed, but reset active
    @(negedge clk); // Reset to 0x34
    if (q !== 8'h34) begin
      $display("FAIL: Short pulse reset failed. Expected 8'h34, got 8'h%h", q);
      errors = errors + 1;
    end

    reset = 0;
    d     = 8'h11;
    @(negedge clk); // Load 0x11
    if (q !== 8'h11) begin $display("FAIL: Post-short-reset load failed. Expected 8'h11, got 8'h%h", q); errors = errors + 1; end
    $display("INFO: Completed short pulse reset test.");


    // Final check and report
    #100; // Give some time for any final propagation
    $display("--------------------------------------------------");
    if (errors == 0) begin
      $display("PASS: All tests completed successfully.");
    end else begin
      $display("FAIL: %0d errors found during simulation.", errors);
    end
    $display("--------------------------------------------------");

    $finish; // End simulation
  end

endmodule

